parameters.jsCode:
console.log($json);

const results = $json.data.results;
const veg = ($json.vegetable || "").trim().toLowerCase();
const targetQty = Number($json.quantity || 500);

if (!veg) throw new Error("Vegetable missing");

const junkWords = [
  "chips","stix","sticks","nachos","snack","mix","masala",
  "fry","frozen","ready","cutlet","soup","powder","paste",
  "sauce","pickle","namkeen","bhujia", "sweet", "Ooty",
"cream","crackers","biscuit","flavour","flavored","combo","cheese","bites","baby","sambar","white","shots","ketchup","Tomato Ketchup"
];

let final = [];

for (const platform in results) {

  if (!Array.isArray(results[platform])) continue;

  results[platform].forEach(item => {

    if (!item.name || item.available !== true) return;

    const name = item.name.toLowerCase();

    const regex = new RegExp(`\\b${veg}\\b`);
    if (!regex.test(name)) return;

    const cookedWords = [
      "paratha","roti","sabzi","curry","gravy","masala",
      "chips","snack","mix","bhujia","namkeen",
      "soup","paste","powder","pickle","fry","cutlet",
      "stix","sticks","crackers","biscuits"
    ];

    if (cookedWords.some(word => name.includes(word))) return;

    if (name.includes("&") || name.includes("flavour") || name.includes("flavored")) return;

    if (name.split(" ").length > 4) return;

    if (!item.quantity) return;

    const qty = item.quantity.toLowerCase();

    const price = Number(item.offer_price || item.mrp || 0);

    let weight = 0;
    if (qty.includes("kg")) {
      weight = parseFloat(qty) * 1000;
    } else if (qty.includes("g")) {
      weight = parseFloat(qty);
    }

    const pricePerKg = weight ? (price / weight) * 1000 : price;

    let score = 0;
    if (name.startsWith(veg)) score += 5;
    if (name.includes(" " + veg + " ")) score += 3;
    if (name.split(" ").length <= 3) score += 2;
    if (junkWords.some(word => name.includes(word))) score -= 5;
    if (name.includes("&")) score -= 3;
    if (name.split(" ").length > 6) score -= 3;
    if (!item.quantity) score -= 2;
    if (
      item.quantity &&
      !item.quantity.toLowerCase().includes("g") &&
      !item.quantity.toLowerCase().includes("kg")
    ) score -= 3;

    const lower = targetQty * 0.8;
    const upper = targetQty * 1.2;

    const deviation = Math.abs(weight - targetQty) / targetQty;

    if (deviation > 0.5) score -= 5;   
    else if (deviation > 0.2) score -= 2; 

    if (score < 2) return;
    final.push({
    app: platform,
    name: item.name,
    price,
    unit: item.quantity || "N/A",
    link: item.deeplink || "#",
    score,
    pricePerKg
});

  });
}

  final.sort((a, b) => {
  if (b.score !== a.score) return b.score - a.score;
  return a.pricePerKg - b.pricePerKg;
});

// remove score before returning
const top5 = final.slice(0, 5).map((item, i) => ({
  app: item.app,
  name: item.name,
  price: item.price,
  unit: item.unit,
  link: item.link,
  price_per_kg: Math.round(item.pricePerKg),
  best: i === 0
}));

return top5.map(item => ({ json: item }));
